"""Schemas for the Prediction resource and the ForecastOutput envelope."""

from __future__ import annotations

import uuid
from datetime import datetime
from typing import Any, Dict, List, Optional

from pydantic import BaseModel, ConfigDict, Field

_SIMULATION_DISCLAIMER = (
    "SIMULATION / EDUCATIONAL USE ONLY. "
    "These probability estimates are generated by a statistical model for "
    "research and educational purposes. They do NOT constitute financial, "
    "betting, or investment advice. Past model performance is not indicative "
    "of future results. Always gamble responsibly and within applicable laws."
)


# ---------------------------------------------------------------------------
# Sub-schemas for nested explanation and evaluation objects
# ---------------------------------------------------------------------------


class PredictionExplanationSchema(BaseModel):
    """SHAP / feature-importance explanation attached to a prediction."""

    model_config = ConfigDict(from_attributes=True)

    id: uuid.UUID = Field(description="Unique explanation record identifier (UUID v4).")
    summary: str = Field(description="Short prose summary of why this prediction was made.")
    top_factors_for: Dict[str, Any] = Field(
        description="Feature name → contribution scores supporting the predicted outcome."
    )
    top_factors_against: Dict[str, Any] = Field(
        description="Feature name → contribution scores opposing the predicted outcome."
    )
    similar_historical: Optional[Dict[str, Any]] = Field(
        default=None,
        description="Up to 5 historical matches that are statistically similar to this fixture.",
    )
    feature_importances: Optional[Dict[str, float]] = Field(
        default=None,
        description="Global feature importance mapping (feature name → importance score).",
    )


class PredictionEvaluationSchema(BaseModel):
    """Post-match evaluation of a prediction against the actual result."""

    model_config = ConfigDict(from_attributes=True)

    id: uuid.UUID = Field(description="Unique evaluation record identifier (UUID v4).")
    actual_outcome: str = Field(
        description="Actual match outcome: 'home', 'draw', or 'away'."
    )
    actual_home_score: Optional[int] = Field(
        default=None, ge=0, description="Actual home team score."
    )
    actual_away_score: Optional[int] = Field(
        default=None, ge=0, description="Actual away team score."
    )
    is_correct: bool = Field(
        description="True when the predicted most-likely outcome matches the actual outcome."
    )
    brier_score: float = Field(
        ge=0.0,
        le=2.0,
        description="Brier score for this prediction (lower is better; perfect = 0).",
    )
    log_loss: Optional[float] = Field(
        default=None,
        description="Log-loss for this prediction (lower is better).",
    )
    evaluated_at: datetime = Field(
        description="Timestamp when the evaluation was recorded (UTC)."
    )


# ---------------------------------------------------------------------------
# Base / Create / Response
# ---------------------------------------------------------------------------


class PredictionBase(BaseModel):
    """Fields shared across prediction schemas."""

    match_id: uuid.UUID = Field(description="UUID of the match this prediction covers.")
    model_version_id: uuid.UUID = Field(
        description="UUID of the model version that produced this prediction."
    )
    predicted_at: datetime = Field(
        description="Timestamp when the prediction was generated (UTC)."
    )
    prediction_type: str = Field(
        max_length=50,
        description="Type of prediction, e.g. 'match_result', 'score', 'btts'.",
    )
    home_win_prob: float = Field(
        ge=0.0,
        le=1.0,
        description="Estimated probability of a home win (0–1).",
    )
    draw_prob: Optional[float] = Field(
        default=None,
        ge=0.0,
        le=1.0,
        description="Estimated probability of a draw (0–1). None for sports without draws.",
    )
    away_win_prob: float = Field(
        ge=0.0,
        le=1.0,
        description="Estimated probability of an away win (0–1).",
    )
    predicted_home_score: Optional[float] = Field(
        default=None,
        ge=0.0,
        description="Expected goals / points for the home team.",
    )
    predicted_away_score: Optional[float] = Field(
        default=None,
        ge=0.0,
        description="Expected goals / points for the away team.",
    )
    confidence: float = Field(
        ge=0.0,
        le=1.0,
        description="Overall model confidence in the prediction (0–1).",
    )
    confidence_interval_low: Optional[float] = Field(
        default=None,
        description="Lower bound of the confidence interval for the top probability.",
    )
    confidence_interval_high: Optional[float] = Field(
        default=None,
        description="Upper bound of the confidence interval for the top probability.",
    )
    is_simulation: bool = Field(
        default=True,
        description=(
            "Always True — all predictions are simulated for educational purposes only. "
            "Not financial or betting advice."
        ),
    )


class PredictionCreate(PredictionBase):
    """Payload required to store a new prediction."""

    features_snapshot: Optional[Dict[str, Any]] = Field(
        default=None,
        description="Raw feature values used as model input (for audit / reproducibility).",
    )
    raw_output: Optional[Dict[str, Any]] = Field(
        default=None,
        description="Raw model output dictionary (probabilities, logits, etc.).",
    )


class PredictionMatchResult(BaseModel):
    """Final score info attached to the inline match summary (v6.1)."""

    model_config = ConfigDict(from_attributes=True)

    home_score: Optional[int] = Field(default=None, ge=0)
    away_score: Optional[int] = Field(default=None, ge=0)
    winner: Optional[str] = Field(
        default=None,
        description="'home' | 'draw' | 'away' | None when unknown.",
    )


class PredictionMatchSummary(BaseModel):
    """Inline match summary embedded in PredictionResponse for feed/list UIs (v6.1)."""

    model_config = ConfigDict(from_attributes=True)

    id: uuid.UUID
    home_team_name: str
    away_team_name: str
    scheduled_at: datetime
    status: str
    league_name: Optional[str] = None
    result: Optional[PredictionMatchResult] = None


class PredictionModelSummary(BaseModel):
    """Inline model summary embedded in PredictionResponse for transparency (v6.2)."""

    # protected_namespaces=() required because `model_type` starts with
    # `model_` which pydantic v2.10+ treats as a namespace violation.
    model_config = ConfigDict(from_attributes=True, protected_namespaces=())

    id: uuid.UUID
    name: str            # "Ensemble v1"
    version: str         # "1.0.0"
    model_type: str      # "elo" | "poisson" | "logistic" | "ensemble"


class PredictionResponse(PredictionBase):
    """Full prediction representation returned by the API."""

    # protected_namespaces=() needed because PredictionBase has
    # model_version_id (inherited) which starts with `model_`.
    model_config = ConfigDict(from_attributes=True, protected_namespaces=())

    id: uuid.UUID = Field(description="Unique prediction identifier (UUID v4).")
    pick: Optional[str] = Field(default=None, description="Predicted outcome: HOME, DRAW, or AWAY.")
    reasoning: Optional[str] = Field(default=None, description="Natural language reasoning.")
    explanation: Optional[PredictionExplanationSchema] = Field(
        default=None,
        description="Feature-level explanation for this prediction (if generated).",
    )
    evaluation: Optional[PredictionEvaluationSchema] = Field(
        default=None,
        description="Post-match evaluation (populated after the match finishes).",
    )
    match: Optional[PredictionMatchSummary] = Field(
        default=None,
        description="Lightweight match summary so feed/list UIs can show teams without a second fetch (v6.1).",
    )
    model_info: Optional[PredictionModelSummary] = Field(
        default=None,
        description="Lightweight model summary for transparency: which model produced this pick (v6.2).",
    )
    created_at: datetime = Field(description="Timestamp when the record was created (UTC).")
    updated_at: datetime = Field(description="Timestamp of the most recent update (UTC).")


# ---------------------------------------------------------------------------
# ForecastOutput — the live forecasting pipeline's output envelope
# ---------------------------------------------------------------------------


class ForecastOutput(BaseModel):
    """
    Structured output from the live forecasting pipeline.

    IMPORTANT — SIMULATION / EDUCATIONAL DISCLAIMER
    -----------------------------------------------
    All probability estimates produced by this platform are for simulation and
    educational research purposes only. They do not constitute financial,
    betting, or investment advice of any kind. The model's past performance
    does not guarantee future accuracy. Use responsibly.
    """

    model_config = ConfigDict(from_attributes=True)

    match_id: uuid.UUID = Field(description="UUID of the match being forecast.")
    model_version_id: uuid.UUID = Field(
        description="UUID of the model version that generated this forecast."
    )
    predicted_at: datetime = Field(description="Timestamp when the forecast was generated (UTC).")

    # Core probabilities
    home_win_prob: float = Field(
        ge=0.0, le=1.0, description="Probability of a home win (0–1)."
    )
    draw_prob: Optional[float] = Field(
        default=None,
        ge=0.0,
        le=1.0,
        description="Probability of a draw (0–1). None for sports without draws.",
    )
    away_win_prob: float = Field(
        ge=0.0, le=1.0, description="Probability of an away win (0–1)."
    )

    # Score forecast
    predicted_home_score: Optional[float] = Field(
        default=None, ge=0.0, description="Expected goals / points for the home side."
    )
    predicted_away_score: Optional[float] = Field(
        default=None, ge=0.0, description="Expected goals / points for the away side."
    )

    # Confidence metrics
    confidence: float = Field(
        ge=0.0,
        le=1.0,
        description=(
            "Composite model confidence score (0–1). "
            "Reflects calibration uncertainty, not certainty of outcome."
        ),
    )
    confidence_interval_low: Optional[float] = Field(
        default=None,
        description="Lower bound of the 90% confidence interval for the leading probability.",
    )
    confidence_interval_high: Optional[float] = Field(
        default=None,
        description="Upper bound of the 90% confidence interval for the leading probability.",
    )

    # Explanation
    explanation: Optional[str] = Field(
        default=None,
        description=(
            "Plain-language summary of the top factors driving this forecast. "
            "Generated for educational purposes only."
        ),
    )
    top_factors: Optional[List[Dict[str, Any]]] = Field(
        default=None,
        description=(
            "List of {feature, direction, importance} dicts identifying the most "
            "influential model features for this fixture."
        ),
    )

    # Disclaimer — always populated with the standard text
    disclaimer: str = Field(
        default=_SIMULATION_DISCLAIMER,
        description=(
            "Mandatory simulation / educational-use disclaimer. "
            "This field is always present and must be surfaced to end users."
        ),
    )
    is_simulation: bool = Field(
        default=True,
        description="Always True — confirms that this output is for simulation use only.",
    )

    # Raw model artefacts (optional, for internal audit)
    features_snapshot: Optional[Dict[str, Any]] = Field(
        default=None,
        description="Feature values used as model input at prediction time.",
    )
    raw_output: Optional[Dict[str, Any]] = Field(
        default=None,
        description="Unprocessed model output dictionary.",
    )
